import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class MapTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor mockConstructorConstructor;

  @Mock
  private Gson mockGson;

  @Mock
  private ObjectConstructor<Object> mockObjectConstructor;

  @Mock
  private TypeAdapter<Object> mockKeyAdapter;

  @Mock
  private TypeAdapter<Object> mockValueAdapter;

  private MapTypeAdapterFactory mapTypeAdapterFactory;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    mapTypeAdapterFactory = new MapTypeAdapterFactory(mockConstructorConstructor, true);
  }

  @Test
  void create_shouldReturnNullIfNotMapType() {
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = mapTypeAdapterFactory.create(mockGson, stringTypeToken);

    assertNull(adapter);
  }

  @Test
  void create_shouldReturnAdapterForMapType() {
    TypeToken<Map<String, String>> mapTypeToken = new TypeToken<Map<String, String>>() {};

    // Mock static method $Gson$Types.getMapKeyAndValueTypes(Type, Class)
    // Since we cannot mock static methods directly here, we simulate the behavior by using real types:
    // key type: String.class, value type: String.class

    when(mockConstructorConstructor.get(mapTypeToken)).thenReturn((ObjectConstructor) mockObjectConstructor);
    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn((TypeAdapter) mockValueAdapter);

    // Spy on mapTypeAdapterFactory to mock getKeyAdapter call
    MapTypeAdapterFactory spyFactory = spy(mapTypeAdapterFactory);
    doReturn(mockKeyAdapter).when(spyFactory).getKeyAdapter(mockGson, String.class);

    TypeAdapter<Map<String, String>> adapter =
        spyFactory.create(mockGson, mapTypeToken);

    assertNotNull(adapter);
    assertEquals(MapTypeAdapterFactory.Adapter.class, adapter.getClass());

    // Verify interactions
    verify(mockConstructorConstructor).get(mapTypeToken);
    verify(mockGson).getAdapter(TypeToken.get(String.class));
    verify(spyFactory).getKeyAdapter(mockGson, String.class);
  }
}
